import sys

def main():
    n = int(input())
    cakes = [list(map(int, sys.stdin.readline().split())) for i in range(n)]
    cakes.sort(key=lambda x: -x[1])

    dp = [0] * n
    for i in range(n):
        dp[i] = cakes[i][1]
        for j in range(i):
            if cakes[j][0] > cakes[i][0]:
                dp[i] = max(dp[i], dp[j] + cakes[i][1])

    print(max(dp))

if __name__ == '__main__':
    main()
